SELECT  player_rankings.id, cast(player_rankings.balls as float)/player_rankings.innings as ggd FROM "player_rankings" INNER JOIN "regions" ON "regions"."id" = "player_rankings"."region_id" INNER JOIN "players" ON "players"."id" = "player_rankings"."player_id" INNER JOIN "seasons" ON "seasons"."id" = "player_rankings"."season_id" INNER JOIN "disciplines" ON "disciplines"."id" = "player_rankings"."discipline_id" WHERE (player_rankings.innings > 0) AND ((seasons.name ilike '%2019/%')) AND ((regions.shortname ilike '%nbv%')) AND ((disciplines.name ilike '%Freie partie k%'))
ORDER BY ggd asc LIMIT 50 OFFSET 0